1	type ScenarioResult = { premium?: number; payout?: number };
2	type ScenarioOutput = { results: ScenarioResult[] };
3	
4	type Item = { type: string; cursed?: boolean; enchantment?: number };
5	type Step = { op: string; items: Item[] };
6	type Customer = { yearsWithMHPCO?: number };
7	type Input = { customer?: Customer; steps: Step[] };
8	
9	const HIGHLY_ENCHANTED_MIN = 5;
10	const LOYALTY_MIN_YEARS = 2;
11	
12	const COMPONENT_BLOCK_SIZE = 3;
13	const COMPONENT_BLOCK_PRICE = 60;
14	const COMPONENT_UNIT_PRICE = 25;
15	
16	const COMPONENT_TYPES = ["rune", "moonstone"] as const;
17	
18	const BASE_BY_ITEM_TYPE: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: COMPONENT_UNIT_PRICE,
24	  moonstone: COMPONENT_UNIT_PRICE,
25	};
26	
27	// Surcharge / discount multipliers expressed as integer percentages so the
28	// pricing arithmetic stays integer-exact until the final divide-and-ceil.
29	const PCT = 100;
30	const PROCESSING_FEE = 5;
31	const CURSED_MULT_PCT = 150;
32	const HIGHLY_ENCHANTED_MULT_PCT = 130;
33	const LOYALTY_MULT_PCT = 80;
34	const FIRST_CONTRACT_MULT_PCT = 110;
35	const AFTER_FIRST_MULT_PCT = 85;
36	
37	const isComponent = (item: Item): boolean =>
38	  (COMPONENT_TYPES as readonly string[]).includes(item.type);
39	
40	const isHighlyEnchanted = (item: Item): boolean =>
41	  (item.enchantment ?? 0) >= HIGHLY_ENCHANTED_MIN;
42	
43	const hasLoyalty = (customer: Customer | undefined): boolean =>
44	  (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_MIN_YEARS;
45	
46	const isAfterFirstStep = (stepIndex: number): boolean => stepIndex >= 1;
47	
48	const isMultiComponentStep = (step: Step): boolean =>
49	  step.items.length >= 2 && step.items.every(isComponent);
50	
51	const baseForComponentCount = (count: number): number => {
52	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
53	  const residual = count % COMPONENT_BLOCK_SIZE;
54	  return blocks * COMPONENT_BLOCK_PRICE + residual * COMPONENT_UNIT_PRICE;
55	};
56	
57	const componentStepBase = (step: Step): number =>
58	  COMPONENT_TYPES.reduce((sum, type) => {
59	    const count = step.items.filter((i) => i.type === type).length;
60	    return sum + baseForComponentCount(count);
61	  }, 0);
62	
63	const stepBase = (step: Step): number =>
64	  isMultiComponentStep(step)
65	    ? componentStepBase(step)
66	    : step.items.reduce((sum, i) => sum + BASE_BY_ITEM_TYPE[i.type], 0);
67	
68	const itemSurchargeMultsPct = (item: Item): number[] => {
69	  const mults: number[] = [];
70	  if (item.cursed) mults.push(CURSED_MULT_PCT);
71	  if (isHighlyEnchanted(item)) mults.push(HIGHLY_ENCHANTED_MULT_PCT);
72	  return mults;
73	};
74	
75	const stepMultsPct = (
76	  customer: Customer | undefined,
77	  stepIndex: number,
78	): number[] => {
79	  if (isAfterFirstStep(stepIndex)) return [AFTER_FIRST_MULT_PCT];
80	  const mults: number[] = [];
81	  if (hasLoyalty(customer)) mults.push(LOYALTY_MULT_PCT);
82	  mults.push(FIRST_CONTRACT_MULT_PCT);
83	  return mults;
84	};
85	
86	const applyMultsAndFee = (base: number, multsPct: number[]): number => {
87	  const numerator = multsPct.reduce((n, m) => n * m, base);
88	  const denominator = Math.pow(PCT, multsPct.length);
89	  return Math.ceil(numerator / denominator) + PROCESSING_FEE;
90	};
91	
92	export function runScenario(input: unknown): ScenarioOutput {
93	  const { customer, steps } = input as Input;
94	  const results = steps.map((step, stepIndex) => {
95	    const multsPct = [
96	      ...itemSurchargeMultsPct(step.items[0]),
97	      ...stepMultsPct(customer, stepIndex),
98	    ];
99	    return { premium: applyMultsAndFee(stepBase(step), multsPct) };
100	  });
101	  return { results };
102	}
